def safe_int_conversion(value):
    try:
        return int(value)
    except TypeError:
        print("TypeError: Provided value is not a type that can be converted to int.")
    except ValueError:
        print("ValueError: Provided string does not contain a valid integer.")

# Testing with different inputs
print(safe_int_conversion(123))        # Works fine
print(safe_int_conversion("456"))    # Works fine
print(safe_int_conversion([1, 2, 3])) # Raises TypeError and handled
print(safe_int_conversion("abc"))    # Raises ValueError and handled
